function _xor(str, key) {
  let out = '';
  for (let i = 0; i < str.length; i++) {
    out += String.fromCharCode(str.charCodeAt(i) ^ key.charCodeAt(i % key.length));
  }
  return out;
}

function _decode(encoded, n) {
  const key = _KEY_SEED + n;
  try {
    return _xor(atob(encoded), key);
  } catch(e) {
    return null;
  }
}

// Utility to encode a letter — call from browser console
window.encodeLetters = function(text, n) {
  const key = _KEY_SEED + n;
  return btoa(_xor(text, key));
};

function getUnlockDate(n) {
  const d = new Date(START_DATE);
  d.setDate(d.getDate() + (n - 1));
  return d;
}

function isUnlocked(n) {
  const unlock = getUnlockDate(n);
  const today = new Date();
  unlock.setHours(0,0,0,0);
  today.setHours(0,0,0,0);
  return today >= unlock;
}

function fmtDate(d) {
  return d.toLocaleDateString('it-IT', { day: 'numeric', month: 'short' });
}

// ---- Modal ----
function createModal() {
  const overlay = document.createElement('div');
  overlay.id = 'letter-overlay';
  overlay.innerHTML = `
    <div class="letter-modal">
      <button class="modal-close" aria-label="Chiudi">×</button>
      <div class="modal-envelope">
        <div class="envelope-flap"></div>
        <div class="envelope-body">
          <div class="envelope-heart">♥</div>
        </div>
      </div>
      <div class="modal-paper">
        <div class="modal-number"></div>
        <div class="modal-date"></div>
        <div class="modal-text"></div>
      </div>
    </div>
  `;
  document.body.appendChild(overlay);

  overlay.querySelector('.modal-close').addEventListener('click', closeModal);
  overlay.addEventListener('click', function(e) {
    if (e.target === overlay) closeModal();
  });
}

function openModal(n) {
  const overlay = document.getElementById('letter-overlay');
  const encoded = LETTERS_DATA[n];
  const unlockDate = getUnlockDate(n);

  overlay.querySelector('.modal-number').textContent = 'Lettera ' + n;
  overlay.querySelector('.modal-date').textContent = fmtDate(unlockDate);

  if (encoded) {
    const text = _decode(encoded, n);
    overlay.querySelector('.modal-text').textContent = text || '— lettera in arrivo —';
  } else {
    overlay.querySelector('.modal-text').innerHTML = '<em>— lettera in arrivo —</em>';
  }

  overlay.classList.add('visible');
  document.body.style.overflow = 'hidden';
}

function closeModal() {
  document.getElementById('letter-overlay').classList.remove('visible');
  document.body.style.overflow = '';
}

// ---- Init ----
document.addEventListener('DOMContentLoaded', function() {
  createModal();

  let unlockedCount = 0;
  for (let i = 1; i <= TOTAL_LETTERS; i++) {
    const card = document.querySelector(`[data-letter="${i}"]`);
    const dateEl = document.getElementById(`date-${i}`);
    const unlocked = isUnlocked(i);

    dateEl.textContent = fmtDate(getUnlockDate(i));

    if (unlocked) {
      card.classList.add('unlocked');
      card.classList.remove('locked');
      unlockedCount++;
    } else {
      card.classList.add('locked');
      card.classList.remove('unlocked');
    }

    card.addEventListener('click', function() {
      if (this.classList.contains('unlocked')) {
        openModal(parseInt(this.getAttribute('data-letter')));
      } else {
        this.classList.add('shake');
        setTimeout(() => this.classList.remove('shake'), 400);
      }
    });
  }

  document.getElementById('unlockedCount').textContent = unlockedCount;
});

setInterval(function() {
  // refresh states every minute
  let count = 0;
  for (let i = 1; i <= TOTAL_LETTERS; i++) {
    const card = document.querySelector(`[data-letter="${i}"]`);
    if (isUnlocked(i)) {
      card.classList.add('unlocked'); card.classList.remove('locked'); count++;
    } else {
      card.classList.add('locked'); card.classList.remove('unlocked');
    }
  }
  document.getElementById('unlockedCount').textContent = count;
}, 60000);